import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/FavoriteButton.css";

function FavoriteButton({ recipe }) {
  let [isFavorite, setIsFavorite] = useState(false);
  let [loading, setLoading] = useState(false);
  let navigate = useNavigate();

  useEffect(() => {
    checkFavorite();
  }, [recipe.api_przepis_id]);

  async function checkFavorite() {
    let loggedUser = localStorage.getItem("loggedUser");

    if (!loggedUser) {
      setIsFavorite(false);
      return;
    }

    let user = JSON.parse(loggedUser);

    try {
      let response = await fetch(
        `http://localhost:5000/api/ulubione/sprawdz?uzytkownik_id=${user.id}&api_przepis_id=${recipe.api_przepis_id}`
      );
      let data = await response.json();
      setIsFavorite(!!data.isFavorite);
    } catch (error) {
      console.log(error);
    }
  }

  async function handleToggle(e) {
    e.preventDefault();
    e.stopPropagation();

    let loggedUser = localStorage.getItem("loggedUser");

    if (!loggedUser) {
      navigate("/logowanie");
      return;
    }

    let user = JSON.parse(loggedUser);

    try {
      setLoading(true);

      if (isFavorite) {
        await fetch("http://localhost:5000/api/ulubione", {
          method: "DELETE",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            uzytkownik_id: user.id,
            api_przepis_id: recipe.api_przepis_id
          })
        });

        setIsFavorite(false);
      } else {
        await fetch("http://localhost:5000/api/ulubione", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            uzytkownik_id: user.id,
            recipe: recipe
          })
        });

        setIsFavorite(true);
      }

      setLoading(false);
      window.dispatchEvent(new Event("favoritesChanged"));
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  }

  return (
    <button
      className={isFavorite ? "favorite-btn active" : "favorite-btn"}
      onClick={handleToggle}
      disabled={loading}
      title={isFavorite ? "Usuń z ulubionych" : "Dodaj do ulubionych"}
    >
      {isFavorite ? "❤" : "♡"}
    </button>
  );
}

export default FavoriteButton;
